/* SQL ID : cmmnCdDAO.selectCmmnCdList 설 명 : 리스트 */ SELECT CMMN_CD_ID , CD , ORG_ID , UP_CD , (SELECT CDNM FROM TB_LMS_CMMN_CD P WHERE P.CD = CMCD.UP_CD AND P.ORG_ID = CMCD.ORG_ID) AS UP_CDNM , CD_SEQNO , CDNM , CD_VL , CD_ENNM , CD_EXPLN , GRPCD , USEYN , RGTR_ID , (SELECT USERNM FROM TB_LMS_USER WHERE USER_ID = CMCD.RGTR_ID) AS RGTR_NM , REG_DTTM , MDFR_ID , (SELECT USERNM FROM TB_LMS_USER WHERE USER_ID = CMCD.MDFR_ID) AS MOD_NM , MOD_DTTM FROM TB_LMS_CMMN_CD CMCD WHERE 1 = 1
AND CMMN_CD_ID = #{cmmnCdId}
AND ORG_ID = #{orgId}
AND ( LOWER(CD) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(CDNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
AND USEYN = #{useyn}
AND CD = #{cd}
AND GRPCD = #{grpcd}
ORDER BY CD_SEQNO ASC

